div.script:
viewPlayer();


  // // If user Logged Out
  var myTabs = document.getElementById('tabsLoggedOut');
  var myTabsCollection = myTabs.querySelectorAll('a');

  var searchField = document.getElementById('search');
  var clearSearchButton = document.getElementById('resetSearchNavButton');
  var matchList = document.getElementById('matchList');
  var filterUnits = document.getElementById('filterUnits');
  var filterSpellbooks = document.getElementById('filterSpellbooks');
  var filterFactions = document.getElementById('filterFactions');
  var filterExpansions = document.getElementById('filterExpansions');
  var filterMaps = document.getElementById('filterMaps');
  var filterFaqs = document.getElementById('filterFaqs');

  var toFilter = [];

  var checkboxes = document.getElementById('checkboxesFilters');
  var checkboxesFilters = document.getElementById('checkboxesFilters').getElementsByTagName('input')

  gatherFilters();

  function gatherFilters() {
    for (var checkbox of checkboxesFilters) {
      if (checkbox.checked === true) {
        // Add if not present
        if (!toFilter.includes(checkbox.value)) {
          toFilter.push(checkbox.value);
        }
      } else {
        // Remove if present
        if (toFilter.includes(checkbox.value)) {
          toFilter.splice(toFilter.indexOf(checkbox.value), 1);
        }
      }
    }
  }

  for (var checkbox of checkboxesFilters) {
    checkbox.addEventListener('change', () => {
      gatherFilters();
      searchIndex(searchField.value)
    });
  }

  searchField.addEventListener('input', () => searchIndex(searchField.value));
  searchField.addEventListener('click', () => searchIndex(searchField.value));

  document.body.addEventListener('click', function(e) {
    if (!searchField.contains(e.target) && !matchList.contains(e.target) && !checkboxes.contains(e.target)) {
      clearSearch();
    }
  });

  function clearSearch() {
    matches = [];
    matchList.scrollTop = 0;
    matchList.classList.add("d-none");
    clearSearchButton.classList.add("d-none");
  }

  var index;
  var searchIndex = async searchText => {
    index = await [{"name":"Great Cthulhu","type":"Faction","product":"Factions","img":"/factions/great-cthulhu/icon.png","url":"/factions/great-cthulhu","keywords":["product","faction"]},{"name":"Acolyte","type":"Cultist","cost":"1","combat":"0","notes":"Spellbook: Dreams","text":"Cost: 1 Combat: 0
